import org.owasp.esapi.ESAPI;
import org.owasp.esapi.codecs.Codec;
import org.owasp.esapi.codecs.HTMLEntityCodec;

import java.io.BufferedReader;
import java.io.IOException;
import java.io.InputStreamReader;

public class XSSFixedCode {
    public static void main(String[] args) {
        try {
            BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
            System.out.print("Enter your name: ");
            String name = br.readLine();

            // Encode user input to prevent XSS
            Codec codec = new HTMLEntityCodec();
            String safeName = ESAPI.encoder().encodeForHTML(codec, name);

            System.out.println("Hello, " + safeName + "!"); // Safe code

        } catch (IOException e) {
            e.printStackTrace();
        }
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
